namespace sv_8c176f65f5b04308868ed5357a56685c.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public record ThemeInfo(Theme Theme, string AccentColor)
{
    public static ThemeInfo Default => new(Theme.Light, "#0d6efd");
}

using Microsoft.AspNetCore.Components;

namespace sv_8c176f65f5b04308868ed5357a56685c.Services;

/// <summary>
/// Scoped service that owns the current theme state and pushes changes
/// to the DI-registered CascadingValueSource so every subscriber
/// (static and interactive) re-renders automatically.
/// </summary>
public sealed class ThemeService
{
    private readonly CascadingValueSource<ThemeInfo> _source;

    public ThemeService(CascadingValueSource<ThemeInfo> source)
    {
        _source = source;
    }

    public ThemeInfo Current { get; private set; } = ThemeInfo.Default;

    /// <summary>
    /// Fired after the theme changes. Components that subscribe must
    /// unsubscribe in Dispose to avoid memory leaks.
    /// </summary>
    public event Action? OnChange;

    public async Task SetThemeAsync(Theme theme)
    {
        Current = Current with { Theme = theme };
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string accentColor)
    {
        Current = Current with { AccentColor = accentColor };
        await NotifyAsync();
    }

    public async Task SetAsync(Theme theme, string accentColor)
    {
        Current = new ThemeInfo(theme, accentColor);
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        await _source.NotifyChangedAsync(Current);
        OnChange?.Invoke();
    }
}

