+// Theme: CascadingValueSource crosses render-mode boundaries (static layout ↔ interactive pages).
+builder.Services.AddCascadingValue(sp =>
+    new CascadingValueSource<ThemeInfo>(ThemeInfo.Default, isFixed: false));
+
+// ThemeService is scoped → one instance per circuit (per user), so users get independent state.
+builder.Services.AddScoped<ThemeService>();

 var app = builder.Build();

