@* Interactive toggle in the sidebar — uses ThemeService to mutate state. *@
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<div class="nav-item px-3 py-2">
    <label class="form-label mb-1 text-light small">Theme</label>
    <select class="form-select form-select-sm" value="@ThemeService.Current.Theme"
            @onchange="OnThemeChanged">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <option value="@t">@t</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
        {
            await ThemeService.SetThemeAsync(theme);
        }
    }

    public void Dispose() => ThemeService.OnChange -= StateHasChanged;
}

