@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card" style="max-width: 480px;">
    <div class="card-body">
        <div class="mb-3">
            <label class="form-label">Theme</label>
            <select class="form-select" value="@selectedTheme"
                    @onchange="OnThemeChanged">
                @foreach (var t in Enum.GetValues<Theme>())
                {
                    <option value="@t">@t</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <input type="color" class="form-control form-control-color"
                   value="@accentColor" @onchange="OnColorChanged" />
        </div>

        <button class="btn btn-primary" @onclick="Save"
                style="background-color: @accentColor; border-color: @accentColor">
            Save Preferences
        </button>

        <span class="ms-2 text-success">@saveMessage</span>
    </div>
</div>

@code {
    private Theme selectedTheme;
    private string accentColor = "#0d6efd";
    private string? saveMessage;

    protected override void OnInitialized()
    {
        selectedTheme = ThemeService.Current.Theme;
        accentColor = ThemeService.Current.AccentColor;
        ThemeService.OnChange += OnExternalChange;
    }

    private void OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var t))
            selectedTheme = t;
    }

    private void OnColorChanged(ChangeEventArgs e)
    {
        accentColor = e.Value?.ToString() ?? accentColor;
    }

    private async Task Save()
    {
        await ThemeService.SetAsync(selectedTheme, accentColor);
        saveMessage = "Saved!";
        await Task.Delay(1500);
        saveMessage = null;
    }

    private void OnExternalChange() => InvokeAsync(StateHasChanged);

    public void Dispose() => ThemeService.OnChange -= OnExternalChange;
}

